{"npsn":"69763277","name":"UPTD SEKOLAH DASAR NEGERI FATUAEL KEC. AMFOANG BARAT DAYA","address":"Fatuael","village":"Manubelon","status":"Negeri","jenjang":"SD","district":"Amfoang Barat Daya","regencyBpsCode":"5301","regencyName":"Kabupaten Kupang","provinceName":"Nusa Tenggara Timur","school_id":"2a50f6b4-811d-46e1-b453-7382227646b8","user_id":"81d9eb1c-4958-494c-ba48-fb169ab7190f"},
